package main

//go:generate go run .

import (
	"math/rand"
	"os"

	"github.com/open-telemetry/opentelemetry-collector-contrib/processor/deltatocumulativeprocessor/internal/metrics"
	"github.com/open-telemetry/opentelemetry-collector-contrib/processor/deltatocumulativeprocessor/internal/testdata/random"
	"go.opentelemetry.io/collector/pdata/pcommon"
	"go.opentelemetry.io/collector/pdata/pmetric"
	"golang.org/x/tools/txtar"
)

const (
	nres    = 2
	nscope  = 2
	nmetric = 2
	total   = nres * nscope * nmetric
)


func main() {
	rand.Seed(0)

	var (
		in   = pmetric.NewMetrics()
		mdIn []pmetric.Metric
	)

	for range nres {
		rm := in.ResourceMetrics().AppendEmpty()
		random.ResourceN(2).MoveTo(rm.Resource())
		for range nscope {
			sm := rm.ScopeMetrics().AppendEmpty()
			random.ScopeN(2).MoveTo(sm.Scope())
			for range nmetric {
				m := sm.Metrics().AppendEmpty()
				random.Sum().CopyTo(m)
				m.Sum().SetAggregationTemporality(pmetric.AggregationTemporalityDelta)
				mdIn = append(mdIn, m)
			}
		}
	}

	var (
		out   = pmetric.NewMetrics()
		mdOut []pmetric.Metric
	)
	in.CopyTo(out)

	metrics.All(out)(func(m metrics.Metric) bool {
		m.Sum().SetAggregationTemporality(pmetric.AggregationTemporalityCumulative)
		mdOut = append(mdOut, m.Metric)
		return true
	})

	streams := make([]pcommon.Map, total*2)
	cumul := make([]int64, len(streams))
	for i := range streams {
		streams[i] = random.Attributes(1)
	}

	for i := range 100 {
		k := rand.Intn(len(streams))
		m := k % total

		dp := pmetric.NewNumberDataPoint()
		streams[k].CopyTo(dp.Attributes())
		dp.SetStartTimestamp(1000)
		dp.SetTimestamp(1000 + pcommon.Timestamp(i*100))

		in := mdIn[m].Sum().DataPoints().AppendEmpty()
		out := mdOut[m].Sum().DataPoints().AppendEmpty()

		dp.CopyTo(in)
		dp.CopyTo(out)

		delta := int64(rand.Intn(128))
		in.SetIntValue(delta)

		cumul[k] += delta
		out.SetIntValue(cumul[k])
	}

	ar := txtar.Archive{
		Comment: []byte("# Code generated by 'go generate .' (generate.go); DO NOT EDIT.\n\n"),
		Files: []txtar.File{
			{Name: "in", Data: marshal(in)},
			{Name: "out", Data: marshal(out)},
		},
	}

	if err := os.WriteFile("1.test", txtar.Format(&ar), 0666); err != nil {
		panic(err)
	}
}
